import { twMerge } from 'tailwind-merge';
import clsx from 'clsx';

interface ButtonProps {
  variant?: 'primary' | 'secondary' | 'outline';
  size?: 'small' | 'medium' | 'large';
  isActive?: boolean;
  isLoading?: boolean;
  className?: string;
  children: React.ReactNode;
  disabled?: boolean;
}

const Button: React.FC<ButtonProps> = ({
  variant = 'primary',
  size = 'medium',
  isActive = false,
  isLoading = false,
  className,
  children,
  disabled = false,
}) => {
  return (
    <button
      className={twMerge(
        // \u7B2C\u4E00\u6B65\uFF1A\u4F7F\u7528 clsx \u6761\u4EF6\u5316\u5730\u6784\u5EFA\u5185\u90E8\u6837\u5F0F
        clsx(
          // \u57FA\u7840\u6837\u5F0F
          'rounded font-semibold transition-colors duration-200',

          // \u6839\u636E variant \u5E94\u7528\u4E0D\u540C\u7684\u989C\u8272\u65B9\u6848
          {
            'bg-blue-500 text-white hover:bg-blue-600': variant === 'primary',
            'bg-gray-500 text-white hover:bg-gray-600': variant === 'secondary',
            'border-2 border-blue-500 text-blue-500 hover:bg-blue-50':
              variant === 'outline',
          },

          // \u6839\u636E size \u5E94\u7528\u4E0D\u540C\u7684\u5C3A\u5BF8
          {
            'px-3 py-1 text-sm': size === 'small',
            'px-4 py-2 text-base': size === 'medium',
            'px-6 py-3 text-lg': size === 'large',
          },

          // \u6839\u636E\u72B6\u6001\u5E94\u7528\u6837\u5F0F
          {
            'ring-2 ring-blue-300 ring-offset-2': isActive,
            'opacity-50 cursor-not-allowed': disabled || isLoading,
            'cursor-wait': isLoading,
          },
        ),
        // \u7B2C\u4E8C\u6B65\uFF1A\u4F7F\u7528 twMerge \u5408\u5E76\u5916\u90E8\u4F20\u5165\u7684 className\uFF0C\u89E3\u51B3\u53EF\u80FD\u7684\u51B2\u7A81
        className,
      )}
      disabled={disabled || isLoading}
    >
      {isLoading ? '\u52A0\u8F7D\u4E2D...' : children}
    </button>
  );
};

export default Button;
