console.log(y); // 1

// null \u4E0D\u4F1A\u89E6\u53D1\u9ED8\u8BA4\u503C
let [z = 1] = [null];
console.log(z); // null

// \u9ED8\u8BA4\u503C\u53EF\u4EE5\u662F\u8868\u8FBE\u5F0F\uFF08\u60F0\u6027\u6C42\u503C\uFF09
const getDefault = () => {
  console.log('\u6267\u884C\u4E86');
  return 1;
};
let [a = getDefault()] = [2]; // \u4E0D\u4F1A\u6267\u884C getDefault
let [b = getDefault()] = []; // \u4F1A\u6267\u884C getDefault\uFF0C\u8F93\u51FA "\u6267\u884C\u4E86"

// \u9ED8\u8BA4\u503C\u53EF\u4EE5\u5F15\u7528\u5176\u4ED6\u53D8\u91CF
let [m = 1, n = m] = [];
