// \u89E3\u6784\u5931\u8D25\u8FD4\u56DE undefined
let { baz } = { foo: 'aaa', bar: 'bbb' };
console.log(baz); // undefined
`,paraId:15,tocIndex:8},{value:"\u5BF9\u8C61\u89E3\u6784\u7684\u5B8C\u6574\u5F62\u5F0F\u662F ",paraId:16,tocIndex:9},{value:"{ \u539F\u5C5E\u6027\u540D: \u65B0\u53D8\u91CF\u540D }",paraId:16,tocIndex:9},{value:"\uFF1A",paraId:16,tocIndex:9},{value:`// \u5C06\u5BF9\u8C61\u7684 foo \u5C5E\u6027\u8D4B\u503C\u7ED9\u53D8\u91CF newFoo
