// console.log(foo); // ReferenceError: foo is not defined

// \u5B9E\u9645\u4E0A\uFF0C\u5BF9\u8C61\u89E3\u6784\u7684\u7B80\u5199\u5F62\u5F0F\u662F\u8FD9\u6837\u7684\uFF1A
