console.log(length); // 5
`,paraId:28,tocIndex:13},{value:"\u89E3\u6784\u8D4B\u503C\u65F6\uFF0C\u5982\u679C\u7B49\u53F7\u53F3\u8FB9\u662F\u6570\u503C\u6216\u5E03\u5C14\u503C\uFF0C\u4F1A\u5148\u8F6C\u4E3A\u5BF9\u8C61\uFF0C\u7136\u540E\u624D\u80FD\u89E3\u6784\u5176\u5C5E\u6027\uFF1A",paraId:29,tocIndex:14},{value:`// \u6570\u503C\u7684\u5305\u88C5\u5BF9\u8C61\u5177\u6709 toString \u65B9\u6CD5
let { toString: s } = 123;
console.log(s === Number.prototype.toString); // true

// \u5E03\u5C14\u503C\u7684\u5305\u88C5\u5BF9\u8C61\u5177\u6709 valueOf \u65B9\u6CD5
let { valueOf: v } = true;
console.log(v === Boolean.prototype.valueOf); // true
`,paraId:30,tocIndex:14},{value:"\u91CD\u8981\u89C4\u5219",paraId:31,tocIndex:14},{value:"\uFF1A",paraId:31,tocIndex:14},{value:"null",paraId:31,tocIndex:14},{value:" \u548C ",paraId:31,tocIndex:14},{value:"undefined",paraId:31,tocIndex:14},{value:" \u65E0\u6CD5\u8F6C\u4E3A\u5BF9\u8C61\uFF0C\u56E0\u6B64\u5BF9\u5B83\u4EEC\u8FDB\u884C\u89E3\u6784\u4F1A\u62A5\u9519\uFF1A",paraId:31,tocIndex:14},{value:`// \u4EE5\u4E0B\u4E24\u884C\u4F1A\u629B\u51FA TypeError
// let { prop: x } = null;      // TypeError
// let { prop: y } = undefined; // TypeError
`,paraId:32,tocIndex:14},{value:"\u51FD\u6570\u53C2\u6570\u53EF\u4EE5\u4F7F\u7528\u89E3\u6784\u8D4B\u503C\uFF0C\u8FD9\u5728\u5B9E\u9645\u5F00\u53D1\u4E2D\u975E\u5E38\u5E38\u7528\uFF1A",paraId:33,tocIndex:15},{value:`// \u6570\u7EC4\u53C2\u6570\u89E3\u6784
function sum([x, y]) {
  return x + y;
}
sum([1, 2]); // 3

// \u5BF9\u8C61\u53C2\u6570\u89E3\u6784
function move({ x = 0, y = 0 } = {}) {
  return [x, y];
}
move({ x: 3, y: 8 }); // [3, 8]
move({ x: 3 }); // [3, 0]
move({}); // [0, 0]
move(); // [0, 0]

// \u6570\u7EC4\u65B9\u6CD5\u4E2D\u7684\u5E94\u7528
[
  [1, 2],
  [3, 4],
].map(([a, b]) => a + b);
// [3, 7]

// undefined \u89E6\u53D1\u9ED8\u8BA4\u503C
[1, undefined, 3].map((x = 'yes') => x);
// [1, 'yes', 3]
`,paraId:34,tocIndex:15},{value:"\u8981\u6CE8\u610F\u533A\u5206\u51FD\u6570\u53C2\u6570\u7684\u9ED8\u8BA4\u503C\u548C\u89E3\u6784\u7684\u9ED8\u8BA4\u503C\uFF1A",paraId:35,tocIndex:16},{value:`// \u5199\u6CD5\u4E00\uFF1A\u51FD\u6570\u53C2\u6570\u7684\u9ED8\u8BA4\u503C\u662F { x: 0, y: 0 }
function move1({ x, y } = { x: 0, y: 0 }) {
  return [x, y];
}
move1({ x: 3, y: 8 }); // [3, 8]
move1({ x: 3 }); // [3, undefined]
move1({}); // [undefined, undefined]
move1(); // [0, 0]

