// \u7B2C\u4E00\u79CD\u60C5\u51B5\uFF1A
// fn \u63D0\u5347\u5230 {} \u5916\u8FB9\uFF0Cfn \u63D0\u5347\u81EA\u6B64\u5904
{
  function fn() {
    console.log('fn');
  }
}

fn();

// \u51FD\u6570\u4F5C\u7528\u57DF
// \u7B2C\u4E8C\u79CD\u60C5\u51B5\uFF1A
!(function () {
  // fn \u63D0\u5347\u81EA\u6B64\u5904
  fn();
  function fn() {
    console.log('fn');
  }
})();

// \u51FD\u6570\u4F5C\u7528\u57DF\u5D4C\u5957\u5757\u7EA7\u4F5C\u7528\u57DF
// \u7B2C\u4E09\u79CD\u60C5\u51B5\uFF1A
(function () {
  if (1) {
    // \u5728\u6D4F\u89C8\u5668\u73AF\u5883\u4E2D\uFF1A
    // 1. fn \u58F0\u660E\u4F1A\u63D0\u5347\u5230\u51FD\u6570\u4F5C\u7528\u57DF\u9876\u90E8\uFF0C\u4F46\u503C\u4E3A undefined
    // 2. \u6267\u884C\u5230\u6B64\u5904\u65F6\uFF0Cfn \u624D\u88AB\u8D4B\u503C\u4E3A\u51FD\u6570
    fn(); // \u53EF\u4EE5\u6B63\u5E38\u8C03\u7528
    function fn() {
      console.log('fn');
    }
  }
})();
