[1, [2, [3, [4]]]].flat(2); // [1, 2, 3, [4]]
[1, [2, [3, [4]]]].flat(Infinity); // [1, 2, 3, 4]

// flatMap - \u6620\u5C04\u540E\u6241\u5E73\u5316
[1, 2, 3].flatMap((x) => [x, x * 2]); // [1, 2, 2, 4, 3, 6]

// \u5B9E\u7528\u573A\u666F\uFF1A\u5904\u7406\u5D4C\u5957\u6570\u636E
