const target = { name: 'object' };
const weakRef = new WeakRef(target);

// \u83B7\u53D6\u5F15\u7528\u7684\u5BF9\u8C61\uFF08\u53EF\u80FD\u5DF2\u88AB\u56DE\u6536\uFF09
